// Pega todas as linhas
const rows = items.map(i => i.json);

// Função para checar se está aprovado
const isApproved = (v) => String(v || '').trim().toLowerCase() === 'aprovado';

// Procura o primeiro item aprovado
const first = rows.find(r => 
  isApproved(r.status_blog) && r.id_post && r.artigo_blog
);

if (!first) return []; // Nenhum aprovado encontrado

// Prepara a saída
const out = { 
  ...first,
  status_retorno: first.status // retorna o status
};

return [{ json: out }];

